<template><main class="page"><section class="panel"><h1>{{ room?.name || '等待房间' }}<span v-if="isHost" class="host-badge">房主</span></h1><div class="grid"><div v-for="p in playersWithHost" :key="p.player.id" class="player-item"><PlayerAvatar :player="p.player"/><span v-if="p.isHost" class="host-tag">房主</span></div></div><p v-if="isHost" class="hint">点击下方按钮开始游戏，开始后会有3秒倒计时</p><p v-else class="hint">等待房主开始游戏...</p><GameButton v-if="isHost" @click="start">开始游戏</GameButton></section></main></template><script setup lang="ts">import { computed } from 'vue'; import { useRoute, useRouter } from 'vue-router'; import { PlayerStatus, PLAYER_COLORS } from '../constants/player'; import { PlayerDirection } from '../constants/game'; import { useRoomStore } from '../stores/roomStore'; import { useGameStore } from '../stores/gameStore'; import PlayerAvatar from '../components/common/PlayerAvatar.vue'; import GameButton from '../components/common/GameButton.vue'; const route=useRoute(); const router=useRouter(); const roomStore=useRoomStore(); const game=useGameStore(); const room=computed(()=>roomStore.rooms.find(r=>r.id===route.params.id)); const isHost=computed(()=>game.isHost(String(route.params.id))); const mockPlayer={id:'p-local',nickname:'你',color:PLAYER_COLORS[0],score:0,status:PlayerStatus.ALIVE,position:{x:5,y:5},direction:PlayerDirection.RIGHT,trail:[],territory:[]}; const players=computed(()=>room.value?.players.length?room.value.players:[mockPlayer]); const playersWithHost=computed(()=>players.value.map(p=>({player:p,isHost:p.id===room.value?.host_id}))); function start(){game.start(String(route.params.id)); game.startCountdown(); router.push('/game/'+route.params.id);}</script><style scoped>.host-badge{display:inline-block;margin-left:8px;padding:2px 10px;background:#f2c94c;color:#333;border-radius:12px;font-size:14px;font-weight:normal}.host-tag{display:block;margin-top:4px;font-size:12px;color:#f2994a;font-weight:bold}.player-item{display:flex;flex-direction:column;align-items:center;padding:8px}.hint{text-align:center;color:#666;margin:16px 0}</style>
